using System;
using System.Reflection;
using System.Linq;

var asm = Assembly.LoadFrom(args[0]);
foreach (var name in new[] { "FactAttribute", "TheoryAttribute" })
{
    var t = asm.GetTypes().FirstOrDefault(x => x.Name == name);
    if (t != null)
    {
        Console.WriteLine($"\n{t.FullName}:");
        foreach (var c in t.GetConstructors(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance))
        {
            var ps = string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}" + (p.HasDefaultValue ? $" = {p.DefaultValue}" : "")));
            var attrs = string.Join(", ", c.GetParameters().SelectMany(p => p.GetCustomAttributes().Select(a => $"[{a.GetType().Name} on {p.Name}]")));
            Console.WriteLine($"  ctor({ps}) {attrs}");
        }
    }
}
EOF
