cd /tmp/inspect && cat > Program.cs << 'EOF'
using System.Reflection.Metadata;
using System.Reflection.PortableExecutable;

using var stream = System.IO.File.OpenRead(args[0]);
using var peReader = new PEReader(stream);
var mr = peReader.GetMetadataReader();

foreach (var tdh in mr.TypeDefinitions)
{
    var td = mr.GetTypeDefinition(tdh);
    var name = mr.GetString(td.Name);
    if (name == "FactAttribute" || name == "TheoryAttribute")
    {
        var ns = mr.GetString(td.Namespace);
        Console.WriteLine($"\n{ns}.{name}:");
        foreach (var mh in td.GetMethods())
        {
            var md = mr.GetMethodDefinition(mh);
            var mname = mr.GetString(md.Name);
            if (mname != ".ctor") continue;
            var sig = md.DecodeSignature(new SignatureTypeProvider(mr), null);
            var access = (md.Attributes & System.Reflection.MethodAttributes.MemberAccessMask) switch {
                System.Reflection.MethodAttributes.Public => "public",
                System.Reflection.MethodAttributes.Family => "protected",
                _ => "private"
            };
            var parms = new List<string>();
            int i = 0;
            foreach (var ph in md.GetParameters())
            {
                var pd = mr.GetParameter(ph);
                var pname = mr.GetString(pd.Name);
                if (string.IsNullOrEmpty(pname)) { i++; continue; }
                var ptype = i < sig.ParameterTypes.Length ? sig.ParameterTypes[i] : "?";
                var cattrs = new List<string>();
                foreach (var cah in pd.GetCustomAttributes())
                {
                    var ca = mr.GetCustomAttribute(cah);
                    if (ca.Constructor.Kind == HandleKind.MemberReference)
                    {
                        var cmr = mr.GetMemberReference((MemberReferenceHandle)ca.Constructor);
                        if (cmr.Parent.Kind == HandleKind.TypeReference)
                        {
                            var ctr = mr.GetTypeReference((TypeReferenceHandle)cmr.Parent);
                            cattrs.Add(mr.GetString(ctr.Name));
                        }
                    }
                }
                var attrStr = cattrs.Count > 0 ? $"[{string.Join(",", cattrs)}] " : "";
                var defVal = pd.Attributes.HasFlag(System.Reflection.ParameterAttributes.HasDefault) ? " = <default>" : "";
                parms.Add($"{attrStr}{ptype} {pname}{defVal}");
                i++;
            }
            Console.WriteLine($"  {access} .ctor({string.Join(", ", parms)})");
        }
    }
}

class SignatureTypeProvider : ISignatureTypeProvider<string, object?>
{
    private readonly MetadataReader _mr;
    public SignatureTypeProvider(MetadataReader mr) => _mr = mr;
    public string GetPrimitiveType(PrimitiveTypeCode tc) => tc.ToString();
    public string GetTypeFromDefinition(MetadataReader r, TypeDefinitionHandle h, byte raw) { var td = r.GetTypeDefinition(h); return r.GetString(td.Name); }
    public string GetTypeFromReference(MetadataReader r, TypeReferenceHandle h, byte raw) { var tr = r.GetTypeReference(h); return r.GetString(tr.Name); }
    public string GetTypeFromSpecification(MetadataReader r, object? gctx, TypeSpecificationHandle h, byte raw) => "spec";
    public string GetSZArrayType(string et) => et + "[]";
    public string GetPointerType(string et) => et + "*";
    public string GetByReferenceType(string et) => "ref " + et;
    public string GetGenericInstantiation(string gt, System.Collections.Immutable.ImmutableArray<string> ta) => $"{gt}<{string.Join(",", ta)}>";
    public string GetGenericMethodParameter(object? gctx, int i) => $"!!{i}";
    public string GetGenericTypeParameter(object? gctx, int i) => $"!{i}";
    public string GetPinnedType(string et) => "pinned " + et;
    public string GetModifiedType(string mod, string ut, bool req) => ut;
    public string GetFunctionPointerType(MethodSignature<string> sig) => "fnptr";
    public string GetArrayType(string et, ArrayShape shape) => et + "[*]";
}
