                            cattrs.Add(mr.GetString(ctr.Name));
                        }
                    }
                }
                var attrStr = cattrs.Count > 0 ? $"[{string.Join(",", cattrs)}] " : "";
                var defVal = pd.Attributes.HasFlag(System.Reflection.ParameterAttributes.HasDefault) ? " = <default>" : "";
                parms.Add($"{attrStr}{ptype} {pname}{defVal}");
                i++;
            }
